-- Engagement survey question bank. Seeds the 66 core questions (active) + 27
-- additional questions from the full 15Five Engage instrument (inactive — turn on
-- individually in Core Data -> Survey Questions). Core question IDs preserved so
-- the imported H1 2025 history stays keyed. Idempotent: ON CONFLICT DO NOTHING so
-- re-runs never clobber admin toggles or custom questions.
CREATE TABLE IF NOT EXISTS "engagement_survey_questions" (
  "id" varchar(64) PRIMARY KEY,
  "text" text NOT NULL,
  "driver" varchar(40),
  "section" varchar(40) NOT NULL,
  "section_title" varchar(120) NOT NULL,
  "section_intro" text NOT NULL DEFAULT '',
  "type" varchar(16) NOT NULL DEFAULT 'likert5',
  "is_active" boolean NOT NULL DEFAULT true,
  "is_core" boolean NOT NULL DEFAULT false,
  "sort_order" integer NOT NULL DEFAULT 0,
  "created_at" timestamptz NOT NULL DEFAULT now()
);
--> statement-breakpoint
ON CONFLICT ("id") DO NOTHING;
--> statement-breakpoint
ALTER TABLE "engagement_survey_responses" ADD COLUMN IF NOT EXISTS "text_answers" jsonb NOT NULL DEFAULT '{}';
